<template>
  <div>
    <h1>Login</h1>
    <b-row class="mt-1 mt-lg-3">
      <b-col lg="8">
        <b-form @submit.stop.prevent="onSubmit">
          <b-form-group label="Username:">
            <b-form-input
              type="text"
              placeholder="Enter Username"
              v-model.trim="$v.form.username.$model"
              :state="validateState('username')"
            ></b-form-input>
            <b-form-invalid-feedback v-if="!$v.form.username.required">
              This field is required.
            </b-form-invalid-feedback>
            <b-form-invalid-feedback v-if="!$v.form.username.minLength">
              Username must be greater than equal 6 characters.
            </b-form-invalid-feedback>
            <b-form-invalid-feedback v-if="!$v.form.username.maxLength">
              Username must be less than equal 32 characters.
            </b-form-invalid-feedback>
          </b-form-group>

          <b-form-group label="Password:">
            <b-form-input
              type="password"
              placeholder="Enter Password"
              v-model="$v.form.password.$model"
              :state="validateState('password')"
            ></b-form-input>
            <b-form-invalid-feedback v-if="!$v.form.password.required">
              This field is required.
            </b-form-invalid-feedback>
            <b-form-invalid-feedback v-if="!$v.form.password.minLength">
              Password must be greater than equal 6 characters.
            </b-form-invalid-feedback>
            <b-form-invalid-feedback v-if="!$v.form.password.maxLength">
              Password must be less than equal 32 characters.
            </b-form-invalid-feedback>
          </b-form-group>

          <b-form-group>
            <b-form-checkbox
              :value="true"
              :unchecked-value="false"
              v-model="form.rememberMe"
            >
              Remember me
            </b-form-checkbox>
          </b-form-group>

          <b-form-group>
            <b-button variant="primary" type="submit" class="mr-1"
              >Sign in</b-button
            >
            <b-button
              variant="outline-primary"
              @click="$router.go(-1)"
              class="ml-1"
              >Back</b-button
            >
          </b-form-group>
        </b-form>
      </b-col>
    </b-row>
  </div>
</template>

<script>
import { required, minLength, maxLength } from "vuelidate/lib/validators";

export default {
  data() {
    return {
      form: {
        username: "",
        password: "",
        rememberMe: false
      }
    };
  },
  validations: {
    form: {
      username: {
        required,
        minLength: minLength(6),
        maxLength: maxLength(32)
      },
      password: {
        required,
        minLength: minLength(6),
        maxLength: maxLength(32)
      }
    }
  },
  methods: {
    validateState(name) {
      const { $dirty, $error } = this.$v.form[name];
      return $dirty ? !$error : null;
    },
    onSubmit() {
      this.$v.form.$touch();
      if (this.$v.form.$anyError) {
        return;
      }
      this.$router.push('/');
    }
  }
};
</script>

<style></style>
